#include<bits/stdc++.h>
using namespace std;
const long long N=5000000,mod=1e9+7;
long long jc[5000010],ny[5000010];
long long C(long long n,long long m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    jc[0]=ny[0]=1;
    for(long long i=1;i<=N;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[N]=fastpow(jc[N],mod-2);
    for(int i=N-1;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n,m;
        scanf("%lld%lld",&n,&m);
        printf("%lld\n",(C(n+m,n)+(n+m-1)*C(n+m-2,n-1)*2%mod)%mod);
    }
    return 0;
}
